/**
 * gen-arch-metafile.mjs — architecture-doc metafile generator
 * ===========================================================
 *
 * GOAL
 *   Emit the structural data for a standalone, interactive SVG document that
 *   draws Hathor's architecture as a top-down layered hierarchy graph, from
 *   `App.tsx` downwards. The volatile structural data is regenerated by this
 *   script so the doc survives `src/` drift.
 *
 * RESOLVED DECISIONS
 *   1. Rendering   — D3.js v7 from CDN (the consuming `architecture.html`).
 *   2. Freshness   — this generator emits a data metafile; the HTML renderer
 *                    is hand-authored and stable.
 *   3. Visibility  — L1 + L2 + L4 show on load; L3 (widgets) hidden until a
 *                    widget chip is clicked.
 *   4. L4 topology — one node per View component, edged to the wrapper it
 *                    renders (per-component).
 *   5. Parsing     — TypeScript Compiler API AST walk, never regex.
 *
 * DATA FLOW
 *   gen-arch-metafile.mjs  ->  docs/architecture-data.js  ->  docs/architecture.html
 *   (run on demand)            (generated metafile)           (hand-authored, D3)
 *   The output is a `<script src>` data file (`window.ARCH_DATA = {...}`), not
 *   a `.json`, because browsers block `fetch()` of local files from a
 *   `file://` page — a `<script>` tag is not blocked, so double-click-to-open
 *   still works.
 *
 * GRAPH MODEL — four layers, top-down
 *   L1  App.tsx (single root)                         — visible
 *   L2  GenericDataViewPage, GenericDetailsPage       — visible
 *   L3  one widget-detail node per opt-in widget      — hidden until expanded
 *   L4  feature View components                       — visible; L2 -> L4
 *       edges skip the L3 rank. `Home` is a leaf straight off App.tsx.
 *
 * PARSING — TypeScript Compiler API
 *   `typescript` is already a Hathor dependency, so this adds no new packages,
 *   no native build, and no WASM blob. All source reading is an AST walk.
 *
 * FAIL-EARLY CONTRACT
 *   Extraction runs as named steps: `parse-routes`, `resolve-imports`,
 *   `detect-wrapper`, `derive-widget-usage`. The first three fail hard — a
 *   failed assertion throws an `ExtractionError` carrying step name,
 *   `file:line:col`, a plain-English expectation, the offending snippet, and a
 *   fix hint, then exits non-zero. `derive-widget-usage` is enrichment and
 *   fails soft (a console warning). Output is assembled fully in memory and
 *   written atomically (tmp file + rename) only if every hard step passes — a
 *   failed run never half-overwrites a previously valid metafile.
 *
 * OUTPUT SCHEMA — window.ARCH_DATA
 *   {
 *     generatedAt: ISO string,
 *     app:      { file, routeCount, protectedCount, publicCount, shell[] },
 *     wrappers: [ { id, name, file, summary, alwaysOn[],
 *                   widgets: [ { key, type, desc, usedBy[] } ] } ],
 *     views:    [ { id, name, file, featureDir, wrapperId|null,
 *                   routes: [ { path, protected } ] } ],
 *   }
 *
 * RUN
 *   node scripts/gen-arch-metafile.mjs   (or: npm run gen:arch)
 */
import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';
import { loadSourceFile, ExtractionError } from './arch-gen/ts-ast.mjs';
import { parseRoutes, resolveRouteImports } from './arch-gen/extract-routes.mjs';
import { detectWrapper, deriveWidgetUsage } from './arch-gen/extract-wrappers.mjs';
import { deriveWidgetBindings } from './arch-gen/extract-bindings.mjs';
import { WRAPPERS, APP_SHELL } from './arch-gen/wrappers-data.mjs';

const REPO_ROOT = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..');
const APP_REL = 'src/App.tsx';
const OUT_REL = 'docs/architecture-data.js';

/** Run every extraction step and assemble the ARCH_DATA object. */
function extract() {
  const appAbs = path.join(REPO_ROOT, APP_REL);
  const { sf, text } = loadSourceFile(appAbs, APP_REL, 'parse-routes');

  const routes = parseRoutes(sf, text, APP_REL);
  const views = resolveRouteImports(routes, sf, text, appAbs, APP_REL, REPO_ROOT);
  for (const v of views) v.wrapperId = detectWrapper(v);
  const usage = deriveWidgetUsage(views);
  const bindings = deriveWidgetBindings(views, REPO_ROOT);

  // A widget belongs to one wrapper; scope its `usedBy` to that wrapper's
  // views so a coarse token match (e.g. `title`, common to both wrappers)
  // cannot leak across.
  const viewWrapper = new Map(views.map(v => [v.name, v.wrapperId]));

  return {
    generatedAt: new Date().toISOString(),
    app: {
      file: APP_REL,
      routeCount: routes.length,
      protectedCount: routes.filter(r => r.protected).length,
      publicCount: routes.filter(r => !r.protected).length,
      shell: APP_SHELL,
    },
    wrappers: WRAPPERS.map(w => ({
      id: w.id,
      name: w.name,
      file: w.file,
      summary: w.summary,
      alwaysOn: w.alwaysOn,
      widgets: w.widgets.map(x => {
        const bs = bindings.get(w.id + '::' + x.key) ?? [];
        // `usedBy` ∪ binding viewIds — bindings are ground truth for slots
        // filled outside the view/config files (e.g. EditorComponent via
        // EditingContext, detailsChildren as JSX children).
        const tokenUsage = (usage.get(x.key) ?? []).filter(n => viewWrapper.get(n) === w.id);
        const combined = [...new Set([...tokenUsage, ...bs.map(b => b.viewId)])];
        return { ...x, usedBy: combined, bindings: bs };
      }),
    })),
    views: views.map(v => ({
      id: v.id,
      name: v.name,
      file: v.file,
      featureDir: v.featureDir,
      wrapperId: v.wrapperId,
      routes: v.routes,
    })),
  };
}

/** Write the metafile atomically (tmp file + rename) — never a partial. */
function write(data) {
  const banner =
    '// GENERATED by scripts/gen-arch-metafile.mjs — do not edit by hand.\n' +
    '// Regenerate with: npm run gen:arch\n';
  const body = `${banner}window.ARCH_DATA = ${JSON.stringify(data, null, 2)};\n`;
  const outAbs = path.join(REPO_ROOT, OUT_REL);
  fs.mkdirSync(path.dirname(outAbs), { recursive: true });
  const tmp = `${outAbs}.tmp`;
  fs.writeFileSync(tmp, body);
  fs.renameSync(tmp, outAbs);
}

try {
  const data = extract();
  write(data);
  const wrapped = data.views.filter(v => v.wrapperId).length;
  console.log(
    `✓ ${OUT_REL} — ${data.app.routeCount} routes, ${data.views.length} views ` +
      `(${wrapped} wrapped, ${data.views.length - wrapped} leaf)`
  );
} catch (err) {
  if (err instanceof ExtractionError) {
    console.error('\n' + err.format() + '\n');
    process.exit(1);
  }
  throw err;
}
